public abstract class Notification {}
public class Email : Notification { public string Body { get; set; } }

public class Router {
    public string Route(Notification n) {
        return n switch {
            Email e => $"Email: {e.Body}",
            _ => "Unknown"
        };
    }
}

examples.toCode:
sealed trait Notification
case class Email(body: String) extends Notification

object Router {
  def route(n: Notification): String = n match {
    case Email(b) => s"Email: $b"
    case _        => "Unknown"
  }
}

